def fizzbuzz(n):
    """Return FizzBuzz output for a number 1 to 100."""
    if n % 15 == 0:
        return "FizzBuzz"
    if n % 3 == 0:
        return "Fizz"
    if n % 5 == 0:
        return "Buzz"
    return str(n)


def print_fizzbuzz():
    """Print FizzBuzz numbers 1 to 100."""
    for i in range(1, 101):
        print(fizzbuzz(i))
